const input = $input.first().json;
const query = (input.query || input.message || input.text || '').trim();
const chatId = (input.chatId || input.chat_id || '-1003688744736').toString();

const now = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Bogota' }));
const hour = now.getHours().toString().padStart(2,'0') + ':' + now.getMinutes().toString().padStart(2,'0');
const todayISO = now.toISOString().split('T')[0];
const dayName = ['Domingo','Lunes','Martes','Miércoles','Jueves','Viernes','Sábado'][now.getDay()];

return { json: { query, chatId, time: { hour, todayISO, dayName, timestamp: now.toISOString() } } };

// ═══════════════════════════════════════════════════════════════
// 🔗 BRIDGE — Parsea + prepara parámetros para cada operación
// ═══════════════════════════════════════════════════════════════

const raw = $input.first().json;
const parser = $('📦 Parser').first().json;

let ai;
try {
  let text = raw.text || raw.output || raw.message || raw.response || '';
  if (typeof text === 'object' && text.intent) { ai = text; }
  else {
    if (typeof text !== 'string') text = JSON.stringify(text);
    text = text.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();
    const m = text.match(/\{[\s\S]*\}/);
    if (m) ai = JSON.parse(m[0]); else throw new Error('No JSON');
  }
} catch(e) {
  ai = { intent: 'ver_agenda', date: parser.time.todayISO, dateEnd: parser.time.todayISO };
}

const intent = ai.intent || 'ver_agenda';
const now = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Bogota' }));

// ═══ Fechas ═══
const dateStr = ai.date || parser.time.todayISO;
const dateEndStr = ai.dateEnd || dateStr;

// TimeMin/TimeMax para queries
let timeMin, timeMax;

if (intent === 'siguiente_evento') {
  // Desde ahora hasta 30 días
  timeMin = now.toISOString();
  const future = new Date(now.getTime() + 30 * 24 * 60 * 60 * 1000);
  timeMax = future.toISOString();
} else {
  timeMin = new Date(dateStr + 'T00:00:00-05:00').toISOString();
  timeMax = new Date(dateEndStr + 'T23:59:59-05:00').toISOString();
}

// ═══ Formato display ═══
const targetDate = new Date(dateStr + 'T12:00:00-05:00');
const opts = { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' };
let dateDisplay = targetDate.toLocaleDateString('es-ES', opts).toUpperCase();
if (dateStr !== dateEndStr) {
  const endDate = new Date(dateEndStr + 'T12:00:00-05:00');
  dateDisplay = `${targetDate.toLocaleDateString('es-ES', { day: 'numeric', month: 'long' })} - ${endDate.toLocaleDateString('es-ES', { day: 'numeric', month: 'long' })}`.toUpperCase();
}

return { json: {
  intent,
  date: dateStr,
  dateEnd: dateEndStr,
  timeMin,
  timeMax,
  dateDisplay,
  isRange: dateStr !== dateEndStr,

  // Para crear
  summary: ai.summary || 'Evento programado',
  description: ai.description || '',
  start: ai.start || '',
  end: ai.end || '',

  // Para borrar/actualizar/buscar
  eventSearch: ai.eventSearch || '',
  updates: ai.updates || {},

  // Meta
  chatId: parser.chatId,
  query: parser.query,
  time: parser.time
}};

// Encontrar el evento más relevante y preparar para borrar
const bridge = $('🔗 Bridge').first().json;
const events = $input.all();
const searchTerm = bridge.eventSearch.toLowerCase();

let found = null;
for (const e of events) {
  const summary = (e.json.summary || '').toLowerCase();
  if (summary.includes(searchTerm)) {
    found = e.json;
    break;
  }
}

if (!found && events.length > 0) {
  // Fuzzy: primer evento que tenga alguna palabra en común
  const searchWords = searchTerm.split(/\s+/);
  for (const e of events) {
    const summary = (e.json.summary || '').toLowerCase();
    if (searchWords.some(w => summary.includes(w))) {
      found = e.json;
      break;
    }
  }
}

return [{ json: {
  eventId: found ? found.id : null,
  eventSummary: found ? found.summary : null,
  found: !!found,
  searchTerm: bridge.eventSearch,
  chatId: bridge.chatId,
  intent: 'borrar_evento',
  bridge
}}];

// Encontrar evento y preparar actualización
const bridge = $('🔗 Bridge').first().json;
const events = $input.all();
const searchTerm = bridge.eventSearch.toLowerCase();
const updates = bridge.updates || {};

let found = null;
for (const e of events) {
  const summary = (e.json.summary || '').toLowerCase();
  if (summary.includes(searchTerm)) {
    found = e.json;
    break;
  }
}

if (!found && events.length > 0) {
  const searchWords = searchTerm.split(/\s+/);
  for (const e of events) {
    const summary = (e.json.summary || '').toLowerCase();
    if (searchWords.some(w => summary.includes(w))) {
      found = e.json;
      break;
    }
  }
}

let updateFields = {};
if (found) {
  if (updates.summary) updateFields.summary = updates.summary;
  if (updates.start) updateFields.start = { dateTime: updates.start, timeZone: 'America/Bogota' };
  if (updates.end) updateFields.end = { dateTime: updates.end, timeZone: 'America/Bogota' };
  if (updates.description) updateFields.description = updates.description;
}

return [{ json: {
  eventId: found ? found.id : null,
  eventSummary: found ? found.summary : null,
  found: !!found,
  updateFields,
  updates,
  searchTerm: bridge.eventSearch,
  chatId: bridge.chatId,
  intent: 'actualizar_evento',
  bridge
}}];

// ═══════════════════════════════════════════════════════════════
// 📊 PREP COMUNICADOR — Unifica resultados de todas las operaciones
// ═══════════════════════════════════════════════════════════════

const bridge = $('🔗 Bridge').first().json;
const now = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Bogota' }));
const currentHour = now.getHours();

let result = {
  type: bridge.intent,
  success: false,
  message: '',
  events: [],
  eventCount: 0,
  dateDisplay: bridge.dateDisplay,
  chatId: bridge.chatId
};

// ═══ Función helper para formatear eventos ═══
function formatEvent(e) {
  const startRaw = e.start?.dateTime || e.start?.date;
  const start = new Date(startRaw);
  const summary = e.summary || 'Sin título';
  let timeStr = e.start?.dateTime
    ? start.toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit', hour12: true, timeZone: 'America/Bogota' })
    : 'Todo el día';
  const isPast = e.start?.dateTime && start < now;
  const isSoon = e.start?.dateTime && !isPast && (start.getTime() - now.getTime() < 30 * 60 * 1000);
  const dateStr = start.toLocaleDateString('es-ES', { weekday: 'short', day: 'numeric', month: 'short' });
  return { summary, timeStr, dateStr, isPast, isSoon, id: e.id };
}

try {
  switch (bridge.intent) {
    case 'ver_agenda': {
      const events = $('📅 Get (Ver)').all();
      const validEvents = events.filter(e => e.json.summary || e.json.start);
      result.events = validEvents.map(e => formatEvent(e.json));
      result.eventCount = result.events.length;
      result.success = true;
      const progressPercent = Math.max(0, Math.min(100, ((currentHour - 6) / 16) * 100));
      result.progressPercent = Math.round(progressPercent);
      result.isToday = bridge.date === bridge.time.todayISO;
      break;
    }

    case 'crear_evento': {
      let created = {};
      try { created = $('📅 Create').first().json; } catch(e) {}
      result.success = !!created.id;
      result.createdEvent = {
        summary: created.summary || bridge.summary,
        start: bridge.start,
        end: bridge.end
      };
      break;
    }

    case 'borrar_evento': {
      let findData = {};
      try { findData = $('🔍 Find (Borrar)').first().json; } catch(e) {}

      if (findData.found) {
        let deleteResult = {};
        try { deleteResult = $('📅 Delete').first().json; } catch(e) {}
        result.success = true; // Si no hubo error, se borró
        result.deletedEvent = findData.eventSummary;
      } else {
        result.success = false;
        result.notFound = true;
        result.searchTerm = bridge.eventSearch;
      }
      break;
    }

    case 'actualizar_evento': {
      let findData = {};
      try { findData = $('🔍 Find (Actualizar)').first().json; } catch(e) {}

      if (findData.found) {
        let updateResult = {};
        try { updateResult = $('📅 Update').first().json; } catch(e) {}
        result.success = true;
        result.updatedEvent = {
          original: findData.eventSummary,
          updates: findData.updates
        };
      } else {
        result.success = false;
        result.notFound = true;
        result.searchTerm = bridge.eventSearch;
      }
      break;
    }

    case 'siguiente_evento': {
      const events = $('📅 Get (Siguiente)').all();
      if (events.length > 0 && events[0].json.summary) {
        result.nextEvent = formatEvent(events[0].json);
        result.success = true;
      } else {
        result.success = true;
        result.noNextEvent = true;
      }
      break;
    }

    case 'buscar_evento': {
      const events = $('📅 Get (Buscar)').all();
      const searchTerm = bridge.eventSearch.toLowerCase();
      const filtered = events.filter(e => {
        const summary = (e.json.summary || '').toLowerCase();
        return summary.includes(searchTerm) || searchTerm.split(/\s+/).some(w => summary.includes(w));
      });
      result.events = filtered.map(e => formatEvent(e.json));
      result.eventCount = result.events.length;
      result.searchTerm = bridge.eventSearch;
      result.success = true;
      break;
    }

    default:
      result.success = false;
      result.message = 'Intención no reconocida';
  }
} catch(e) {
  result.success = false;
  result.error = e.message;
}

return { json: {
  result,
  chatId: bridge.chatId,
  query: bridge.query,
  time: bridge.time
}};

