const raw = $input.first().json;
let final;
try {
  let text = raw.text || raw.output || raw.message || raw.response || '';
  if (typeof text === 'object' && text.telegramPayload) { final = text; }
  else {
    if (typeof text !== 'string') text = JSON.stringify(text);
    text = text.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();
    const m = text.match(/\{[\s\S]*\}/);
    if (m) final = JSON.parse(m[0]); else throw new Error('No JSON');
  }
} catch(e) {
  const prep = $('📊 Prep Comunicador').first().json;
  final = {
    telegramPayload: { chat_id: prep.chatId, text: '📅 Operación completada.', parse_mode: 'Markdown' },
    toolResponse: '📅 Calendario procesado'
  };
}
return [{ json: final }];

// Tag para eventos no encontrados (borrar)
const find = $input.first().json;
return [{ json: { ...find, notFoundBranch: true } }];

// Tag para eventos no encontrados (actualizar)
const find = $input.first().json;
return [{ json: { ...find, notFoundBranch: true } }];

// Tag después de delete exitoso
const prev = $('🔍 Find (Borrar)').first().json;
return [{ json: { ...prev, deleteSuccess: true } }];

// Tag después de update exitoso
const prev = $('🔍 Find (Actualizar)').first().json;
const updated = $input.first().json;
return [{ json: { ...prev, updateSuccess: true, updatedResult: updated } }];
